module RefModule(
    input clk,
    input reset,
    input [15:0] in,
    output reg [15:0] out);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            out <= 16'b0;
        else
            out <= in << 1;
    end
endmodule
